using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 0);

// Load data
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

// Build training pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features", nameof(CustomerData.Age), nameof(CustomerData.Income), "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(CustomerData.Churned), featureColumnName: "Features"));

// Train model
var model = pipeline.Fit(dataView);
var predictor = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "Churn Predictor API - POST to /predict with customer data");

app.MapPost("/predict", (CustomerInput input) =>
{
    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };
    var prediction = predictor.Predict(data);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability
    });
});

app.Run();

// Input model for the API
public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

// ML.NET data class matching CSV columns
public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Label")] public bool Churned { get; set; }
}

// ML.NET prediction output
public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

